package com.example.mfabackup.controller;

import com.example.mfabackup.entity.User;
import com.example.mfabackup.service.MfaService;
import com.example.mfabackup.service.UserService;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpSession;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.servlet.mvc.support.RedirectAttributes;

import java.util.List;
import java.util.Optional;

@Controller
@RequestMapping("/mfa")
public class MfaController {

    private final MfaService mfaService;
    private final UserService userService;

    public MfaController(MfaService mfaService, UserService userService) {
        this.mfaService = mfaService;
        this.userService = userService;
    }

    @GetMapping("/setup")
    public String showMfaSetup(Model model) {
        User currentUser = (User) SecurityContextHolder.getContext().getAuthentication().getPrincipal();
        if (currentUser.isMfaEnabled()) {
            return "redirect:/home"; // MFA already enabled
        }

        String secret = mfaService.generateSecretKey();
        currentUser.setMfaSecret(secret); // Temporarily store in session/model until confirmed

        String qrCodeUrl = mfaService.getQrCodeImageUrl(secret, currentUser.getUsername());

        model.addAttribute("qrCodeUrl", qrCodeUrl);
        model.addAttribute("secret", secret);
        model.addAttribute("username", currentUser.getUsername());
        return "mfa-setup";
    }

    @PostMapping("/setup")
    public String setupMfa(@RequestParam("code") String code,
                           @RequestParam("secret") String secret,
                           HttpServletRequest request,
                           RedirectAttributes redirectAttributes,
                           Model model) {
        User currentUser = (User) SecurityContextHolder.getContext().getAuthentication().getPrincipal();

        if (mfaService.verifyTotpCode(secret, code)) {
            currentUser.setMfaEnabled(true);
            currentUser.setMfaSecret(secret);
            userService.saveUser(currentUser);

            List<String> backupCodes = mfaService.generateBackupCodes(currentUser);
            redirectAttributes.addFlashAttribute("backupCodes", backupCodes);
            redirectAttributes.addFlashAttribute("mfaSetupSuccess", true);
            return "redirect:/mfa/backup-codes";
        } else {
            model.addAttribute("errorMessage", "Invalid TOTP code. Please try again.");
            String qrCodeUrl = mfaService.getQrCodeImageUrl(secret, currentUser.getUsername());
            model.addAttribute("qrCodeUrl", qrCodeUrl);
            model.addAttribute("secret", secret);
            model.addAttribute("username", currentUser.getUsername());
            return "mfa-setup";
        }
    }

    @GetMapping("/verify")
    public String showMfaVerification(Model model, HttpServletRequest request) {
        User currentUser = (User) SecurityContextHolder.getContext().getAuthentication().getPrincipal();
        if (!currentUser.isMfaEnabled()) {
            return "redirect:/home"; // MFA not enabled, no need to verify
        }

        // Check if the user is already fully authenticated (e.g., after using backup code)
        // This is a simple check; a more robust solution might use custom authentication tokens
        // For this example, we'll assume if they reach /mfa/verify, they need to verify
        return "mfa-verify";
    }

    @PostMapping("/verify")
    public String verifyMfa(@RequestParam("code") String code, Model model) {
        User currentUser = (User) SecurityContextHolder.getContext().getAuthentication().getPrincipal();

        if (mfaService.verifyTotpCode(currentUser.getMfaSecret(), code)) {
            // MFA successful, proceed to home
            return "redirect:/home";
        } else {
            model.addAttribute("errorMessage", "Invalid TOTP code. Please try again.");
            return "mfa-verify";
        }
    }

    @GetMapping("/backup-codes")
    public String showBackupCodes(Model model) {
        if (!model.containsAttribute("backupCodes")) {
            // If the user navigates directly here, or refreshes,
            // we don't want to show blank codes or regenerate.
            // This page should only be accessible immediately after MFA setup.
            return "redirect:/home";
        }
        return "mfa-backup-codes";
    }

    @GetMapping("/verify-backup-code")
    public String showBackupCodeLoginForm() {
        return "mfa-backup-code-login";
    }

    @PostMapping("/verify-backup-code")
    public String verifyBackupCodeLogin(@RequestParam("username") String username,
                                        @RequestParam("backupCode") String backupCode,
                                        HttpServletRequest request,
                                        Model model) {
        Optional<User> userOptional = userService.findByUsername(username);
        if (userOptional.isEmpty() || !userOptional.get().isMfaEnabled()) {
            model.addAttribute("errorMessage", "Invalid username or MFA not enabled.");
            return "mfa-backup-code-login";
        }

        User user = userOptional.get();
        if (mfaService.useBackupCode(user, backupCode)) {
            // Authenticate the user programmatically
            Authentication authentication = new UsernamePasswordAuthenticationToken(user, user.getPassword(), user.getAuthorities());
            SecurityContextHolder.getContext().setAuthentication(authentication);

            // Redirect to home page
            return "redirect:/home";
        } else {
            model.addAttribute("errorMessage", "Invalid or used backup code.");
            return "mfa-backup-code-login";
        }
    }
}

