package com.example.mfabackup.service;

import com.example.mfabackup.entity.BackupCode;
import com.example.mfabackup.entity.User;
import com.example.mfabackup.repository.BackupCodeRepository;
import com.example.mfabackup.repository.UserRepository;
import com.example.mfabackup.util.TotpUtil;
import com.google.zxing.WriterException;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.io.IOException;
import java.util.ArrayList;
import java.util.List;
import java.util.Optional;
import java.util.UUID;
import java.util.stream.Collectors;

@Service
public class MfaService {

    @Value("${application.name:MFA-Backup-App}")
    private String applicationName;

    private final UserRepository userRepository;
    private final BackupCodeRepository backupCodeRepository;
    private final PasswordEncoder passwordEncoder;

    public MfaService(UserRepository userRepository, BackupCodeRepository backupCodeRepository, PasswordEncoder passwordEncoder) {
        this.userRepository = userRepository;
        this.backupCodeRepository = backupCodeRepository;
        this.passwordEncoder = passwordEncoder;
    }

    public String generateSecretKey() {
        return TotpUtil.generateSecret();
    }

    public String getQrCodeImageUrl(String secret, String username) {
        try {
            return TotpUtil.getQrCodeImageUrl(secret, username, applicationName);
        } catch (WriterException | IOException e) {
            throw new RuntimeException("Error generating QR code", e);
        }
    }

    public boolean verifyTotpCode(String secret, String code) {
        return TotpUtil.validateCode(secret, code);
    }

    @Transactional
    public List<String> generateBackupCodes(User user) {
        // Delete existing backup codes first, if any
        user.getBackupCodes().clear();

        List<String> rawCodes = new ArrayList<>();
        List<BackupCode> hashedCodes = new ArrayList<>();
        for (int i = 0; i < 10; i++) { // Generate 10 backup codes
            String code = generateRandomCode();
            rawCodes.add(code);
            hashedCodes.add(new BackupCode(passwordEncoder.encode(code), user));
        }
        user.getBackupCodes().addAll(hashedCodes); // Cascade will save them
        userRepository.save(user); // Ensure user object is managed and changes are persisted
        return rawCodes;
    }

    @Transactional
    public boolean useBackupCode(User user, String inputCode) {
        List<BackupCode> unusedCodes = user.getBackupCodes().stream()
                .filter(b -> !b.isUsed())
                .collect(Collectors.toList());

        for (BackupCode backupCode : unusedCodes) {
            if (passwordEncoder.matches(inputCode, backupCode.getCodeHash())) {
                backupCode.setUsed(true);
                backupCodeRepository.save(backupCode); // Persist the change
                return true;
            }
        }
        return false;
    }


    private String generateRandomCode() {
        return UUID.randomUUID().toString().substring(0, 8).toUpperCase(); // 8-character alphanumeric code
    }
}

