package com.example.mfabackup.util;

import com.google.zxing.BarcodeFormat;
import com.google.zxing.WriterException;
import com.google.zxing.client.j2se.MatrixToImageWriter;
import com.google.zxing.common.BitMatrix;
import com.google.zxing.qrcode.QRCodeWriter;
import dev.samuelwrites.otp.Totp;

import java.io.ByteArrayOutputStream;
import java.io.IOException;
import java.util.Base64;

public class TotpUtil {

    private static final int QR_CODE_WIDTH = 200;
    private static final int QR_CODE_HEIGHT = 200;

    /**
     * Generates a new random TOTP secret key.
     * @return A base32 encoded secret key.
     */
    public static String generateSecret() {
        return new Totp().generateSecret();
    }

    /**
     * Generates a QR code image URL for a given TOTP secret.
     * The URL can be embedded in an HTML img tag.
     * @param secret The TOTP secret key.
     * @param account The user's account identifier (e.g., email or username).
     * @param issuer The issuer name (e.g., your application name).
     * @return A data URI string representing the QR code image.
     * @throws WriterException If there's an error in QR code generation.
     * @throws IOException If there's an error writing the image to byte array.
     */
    public static String getQrCodeImageUrl(String secret, String account, String issuer) throws WriterException, IOException {
        String otpAuthUrl = String.format("otpauth://totp/%s:%s?secret=%s&issuer=%s", issuer, account, secret, issuer);

        QRCodeWriter qrCodeWriter = new QRCodeWriter();
        BitMatrix bitMatrix = qrCodeWriter.encode(otpAuthUrl, BarcodeFormat.QR_CODE, QR_CODE_WIDTH, QR_CODE_HEIGHT);

        ByteArrayOutputStream pngOutputStream = new ByteArrayOutputStream();
        MatrixToImageWriter.writeToStream(bitMatrix, "PNG", pngOutputStream);
        byte[] pngData = pngOutputStream.toByteArray();
        return "data:image/png;base64," + Base64.getEncoder().encodeToString(pngData);
    }

    /**
     * Validates a TOTP code against a secret key.
     * @param secret The TOTP secret key.
     * @param code The code entered by the user.
     * @return True if the code is valid, false otherwise.
     */
    public static boolean validateCode(String secret, String code) {
        Totp totp = new Totp(secret);
        return totp.verify(code);
    }
}

